 87→        throw {staus: 400, error: 'userId is undefined'};
 88→    }
 89→    if(!name || typeof name !== 'string' || name.length > 20){
 90→        throw {status: 400, error: 'name should be a string and not more than 20 characters'}
 91→    }
 92→    if(!bio || typeof bio !== 'string' || bio.length > 150){
 93→        throw {status: 400, error: 'bio should be a string and not more than 150 characters'}
 94→    }
 95→
 96→    // Validate username if provided
 97→    let validatedUsername = null;
 98→    if(username && typeof username === 'string'){
 99→        const trimmed = username.trim().toLowerCase();
100→        if(trimmed.length < 3 || trimmed.length > 50){
101→            throw {status: 400, error: 'username must be 3-50 characters'};
102→        }
103→        if(!/^[a-z0-9-]+$/.test(trimmed)){
104→            throw {status: 400, error: 'username can only contain lowercase letters, numbers, and hyphens'};
105→        }
106→        // Check uniqueness
107→        const {data: existing} = await supabase
108→            .from('users')
109→            .select('id')
110→            .ilike('username', trimmed)
111→            .limit(1);
112→        if(existing && existing.length > 0){
113→            throw {status: 409, error: 'username is already taken'};
114→        }
115→        validatedUsername = trimmed;
116→    }
117→
118→    let publicUrl = null;
119→    if(image){
120→        const dataUrl = await imageUploader(image, userId, 'avatars');
121→
122→        publicUrl = dataUrl;
123→    }
124→
125→    const data = {
126→        bio: bio,
127→        name: name,
128→        id: userId,
129→        user_email: userEmail || null,
130→        image_url: publicUrl ? publicUrl : null
131→    }
132→
133→    if(validatedUsername){
134→        data.username = validatedUsername;
135→    }
136→
137→    const {data: uploadData, error:errorUploadData} = await supabase
138→    .from('users')
139→    .insert([data])
140→
141→    if(errorUploadData){
142→        console.error('supabase error:', errorUploadData.message);
143→        throw {status:500, error:'supabase error while uploading data'}
144→    }
145→
146→    return true;
